/// <summary>
/// Tarefa #34 — contrato adicional para habilidades ACTIVAS (botão de
/// Habilidade) que a HUD precisa de representar de forma uniforme: cooldown,
/// estado activo e disponibilidade.
///
/// Estende <see cref="IAbility"/> (que já dá <c>CooldownRemaining</c> e
/// <c>IsActive</c>) com:
///
/// - <see cref="CooldownDuration"/>: duração TOTAL do cooldown, usada pela HUD
///   para normalizar uma barra/anel de progresso (CooldownRemaining /
///   CooldownDuration). Um valor de 0 significa "sem cooldown" — a HUD não
///   mostra qualquer indicador de cooldown para esta habilidade (habilidades
///   passivas ou instantâneas sem cooldown próprio).
/// - <see cref="CanActivate"/>: true se a habilidade pode ser activada AGORA
///   (cooldown terminado, requisitos da forma/estado cumpridos) — usado pela
///   HUD para indicar disponibilidade (ex: ícone acinzentado quando false).
///
/// TODAS as habilidades activas (ligadas a PrimaryAbility / botão de
/// Habilidade) devem implementar esta interface, para que
/// <see cref="AbilityRouter.GetPrimaryAbilityCooldownSource"/> e
/// <see cref="HUDController"/> as tratem de forma uniforme. Habilidades sem
/// cooldown próprio devolvem 0 em CooldownDuration (e portanto não mostram
/// indicador), mas ainda implementam a interface (sem custo extra).
/// </summary>
public interface IActiveAbility : IAbility
{
    /// <summary>Duração total do cooldown (segundos). 0 = sem cooldown — a HUD não mostra indicador para esta habilidade.</summary>
    float CooldownDuration { get; }

    /// <summary>True se a habilidade pode ser activada agora (cooldown terminado, requisitos da forma cumpridos, etc.) — disponibilidade mostrada pela HUD.</summary>
    bool CanActivate { get; }

    /// <summary>
    /// AnimalsDebugPanel (aba "Habilidades"): zera imediatamente o cooldown
    /// desta habilidade, sem esperar o tempo normal. Habilidades sem cooldown
    /// próprio (CooldownDuration == 0) implementam isto como no-op.
    /// </summary>
    void ResetCooldown();
}
